#!/bin/bash

# Qveris Tool Search Script
# Usage: ./qveris.sh "your natural language query"

set -e

# Configuration
QVERIS_API_KEY="${QVERIS_API_KEY:-sk-WagpbSeBN1oiytUOYAvcuhhFNslmqsdXhSQJbkXMris}"
QVERIS_API_URL="https://api.qveris.ai/v1"

# Check if query is provided
if [ $# -eq 0 ]; then
    echo "Usage: ./qveris.sh <natural language query>"
    echo "Example: ./qveris.sh 'convert text to speech'"
    exit 1
fi

QUERY="$1"

echo "🔍 Searching Qveris for: $QUERY"
echo ""

# Make API request to search tools
RESPONSE=$(curl -s -X POST "${QVERIS_API_URL}/search" \
    -H "Authorization: Bearer ${QVERIS_API_KEY}" \
    -H "Content-Type: application/json" \
    -d "{
        \"query\": \"${QUERY}\",
        \"limit\": 5
    }" 2>/dev/null || echo '{"error": "Request failed"}')

# Check if response contains error
if echo "$RESPONSE" | grep -q '"error"'; then
    echo "❌ Error: Failed to search tools"
    echo "Response: $RESPONSE"
    exit 1
fi

# Parse and display results
echo "📋 Found Tools:"
echo "================"
echo "$RESPONSE" | node -e "
const data = '';
process.stdin.on('data', chunk => data.push(chunk));
process.stdin.on('end', () => {
    try {
        const result = JSON.parse(data.join(''));
        if (result.tools && result.tools.length > 0) {
            result.tools.forEach((tool, index) => {
                console.log(\`\${index + 1}. \${tool.name}\`);
                console.log(\`   Description: \${tool.description || 'N/A'}\`);
                console.log(\`   Category: \${tool.category || 'N/A'}\`);
                if (tool.endpoint) {
                    console.log(\`   Endpoint: \${tool.endpoint}\`);
                }
                console.log('');
            });
        } else {
            console.log('No tools found for this query.');
        }
    } catch (e) {
        console.log('Raw response:', data.join(''));
    }
});
"

echo ""
echo "💡 To execute a tool, use the endpoint information above."

