node -e "
const data = require('/tmp/hayao_10y_data.json');
const prices = data[0];

// 基本统计
const firstPrice = prices[0].close;
const lastPrice = prices[prices.length - 1].close;
const maxPrice = Math.max(...prices.map(p => p.high));
const minPrice = Math.min(...prices.map(p => p.low));
const maxPriceDate = prices.find(p => p.high === maxPrice).time;
const minPriceDate = prices.find(p => p.low === minPrice).time;

// 计算收益率
const totalReturn = ((lastPrice - firstPrice) / firstPrice * 100).toFixed(2);
const maxReturn = ((maxPrice - firstPrice) / firstPrice * 100).toFixed(2);
const maxLoss = ((minPrice - firstPrice) / firstPrice * 100).toFixed(2);

// 年度数据
const yearlyData = {};
prices.forEach(p => {
  const year = p.time.substring(0, 4);
  if (!yearlyData[year]) yearlyData[year] = { prices: [] };
  yearlyData[year].prices.push(p.close);
});

Object.keys(yearlyData).forEach(year => {
  const yearPrices = yearlyData[year].prices;
  yearlyData[year].open = yearPrices[0];
  yearlyData[year].close = yearPrices[yearPrices.length - 1];
  yearlyData[year].high = Math.max(...yearPrices);
  yearlyData[year].low = Math.min(...yearPrices);
  yearlyData[year].return = ((yearlyData[year].close - yearlyData[year].open) / yearlyData[year].open * 100).toFixed(2);
});

console.log('=== 哈药股份 (600664) 10年投资回顾 ===\n');
console.log('持有期: 2015年3月 - 2025年3月 (约10年)');
console.log('初始价格: ¥' + firstPrice.toFixed(2));
console.log('当前价格: ¥' + lastPrice.toFixed(2));
console.log('总收益率: ' + totalReturn + '%');
console.log('年化收益率: ' + (Math.pow(1 + totalReturn/100, 1/10) - 1).toFixed(4) * 100 + '%');
console.log('\n=== 价格波动 ===');
console.log('最高价: ¥' + maxPrice.toFixed(2) + ' (' + maxPriceDate + ')');
console.log('最低价: ¥' + minPrice.toFixed(2) + ' (' + minPriceDate + ')');
console.log('最大涨幅: +' + maxReturn + '%');
console.log('最大跌幅: ' + maxLoss + '%');
console.log('\n=== 年度表现 ===');
Object.keys(yearlyData).slice(0, 10).forEach(year => {
  const d = yearlyData[year];
  const emoji = parseFloat(d.return) > 0 ? '📈' : '📉';
  console.log(year + ': ' + emoji + ' ' + (d.return > 0 ? '+' : '') + d.return + '% (高:¥' + d.high.toFixed(2) + ' 低:¥' + d.low.toFixed(2) + ')');
});
